        const root = dsu.find(x);
        const heap = componentHeaps.get(root)!;
        while (true) {
          const top = heap.peek();
          if (top === undefined) {
            result.push(-1);
            break;
          }
          if (online[top]) {
            result.push(top);
            break;
          } else {
            heap.pop();
          }
        }
      }
    } else {
      online[x] = false;
    }
  }

  return result;
}
